func (e *TooManyValuesForParamError) Error() string {
	return fmt.Sprintf("Expected one value for %s, got %d", e.ParamName, e.Count)
}

// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of http.ServeMux.
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	ServeHTTP(w http.ResponseWriter, r *http.Request)
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("POST "+options.BaseURL+"/auth/forgot-password", wrapper.ForgotPassword)
	m.HandleFunc("POST "+options.BaseURL+"/auth/login", wrapper.Login)
	m.HandleFunc("POST "+options.BaseURL+"/auth/logout", wrapper.Logout)
	m.HandleFunc("GET "+options.BaseURL+"/auth/me", wrapper.GetMe)
	m.HandleFunc("POST "+options.BaseURL+"/auth/reset-password", wrapper.ResetPassword)
	m.HandleFunc("GET "+options.BaseURL+"/auth/sessions", wrapper.ListSessions)
	m.HandleFunc("DELETE "+options.BaseURL+"/auth/sessions/{id}", wrapper.DeleteSession)
	m.HandleFunc("GET "+options.BaseURL+"/dashboard/stats", wrapper.GetDashboardStats)
	m.HandleFunc("POST "+options.BaseURL+"/emails/{id}/retry", wrapper.RetryEmail)
	m.HandleFunc("GET "+options.BaseURL+"/groups", wrapper.ListGroups)
	m.HandleFunc("POST "+options.BaseURL+"/groups", wrapper.CreateGroup)
	m.HandleFunc("DELETE "+options.BaseURL+"/groups/{id}", wrapper.DeleteGroup)
	m.HandleFunc("GET "+options.BaseURL+"/groups/{id}", wrapper.GetGroup)
	m.HandleFunc("PATCH "+options.BaseURL+"/groups/{id}", wrapper.UpdateGroup)
	m.HandleFunc("GET "+options.BaseURL+"/groups/{id}/members", wrapper.ListGroupMembers)
	m.HandleFunc("POST "+options.BaseURL+"/groups/{id}/members", wrapper.AddGroupMember)
	m.HandleFunc("DELETE "+options.BaseURL+"/groups/{id}/members/{person_id}", wrapper.RemoveGroupMember)
	m.HandleFunc("GET "+options.BaseURL+"/invites", wrapper.ListInvites)
	m.HandleFunc("POST "+options.BaseURL+"/invites", wrapper.CreateInvite)
	m.HandleFunc("DELETE "+options.BaseURL+"/invites/{id}", wrapper.DeleteInvite)
	m.HandleFunc("GET "+options.BaseURL+"/invites/{id}", wrapper.GetInvite)
	m.HandleFunc("PATCH "+options.BaseURL+"/invites/{id}", wrapper.UpdateInvite)
	m.HandleFunc("GET "+options.BaseURL+"/invites/{id}/phases", wrapper.ListInvitePhases)
	m.HandleFunc("POST "+options.BaseURL+"/invites/{id}/phases", wrapper.CreateInvitePhase)
	m.HandleFunc("DELETE "+options.BaseURL+"/invites/{id}/phases/{phase_id}", wrapper.DeleteInvitePhase)
	m.HandleFunc("POST "+options.BaseURL+"/invites/{id}/start", wrapper.StartInvite)
	m.HandleFunc("GET "+options.BaseURL+"/invites/{id}/status", wrapper.GetInviteStatus)
	m.HandleFunc("GET "+options.BaseURL+"/persons", wrapper.ListPersons)
	m.HandleFunc("POST "+options.BaseURL+"/persons", wrapper.CreatePerson)
	m.HandleFunc("DELETE "+options.BaseURL+"/persons/{id}", wrapper.DeletePerson)
	m.HandleFunc("GET "+options.BaseURL+"/persons/{id}", wrapper.GetPerson)
	m.HandleFunc("PATCH "+options.BaseURL+"/persons/{id}", wrapper.UpdatePerson)
	m.HandleFunc("GET "+options.BaseURL+"/respond/{token}", wrapper.GetInviteForResponse)
	m.HandleFunc("POST "+options.BaseURL+"/respond/{token}", wrapper.RespondToInvite)
	m.HandleFunc("GET "+options.BaseURL+"/tags", wrapper.ListTags)
	m.HandleFunc("POST "+options.BaseURL+"/tags", wrapper.CreateTag)
	m.HandleFunc("DELETE "+options.BaseURL+"/tags/{id}", wrapper.DeleteTag)
	m.HandleFunc("GET "+options.BaseURL+"/tags/{id}", wrapper.GetTagUsage)
	m.HandleFunc("PATCH "+options.BaseURL+"/tags/{id}", wrapper.UpdateTag)

	return m
}

